import React, { useState, useEffect } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Navbar = () => {
  const { user, logout, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const handleLogout = () => { logout(); navigate("/"); setMenuOpen(false); };
  const isActive = (path) => location.pathname === path;

  const navStyle = {
    position: "sticky", top: 0, zIndex: 999,
    background: scrolled ? "rgba(7,7,15,0.97)" : "rgba(7,7,15,0.7)",
    backdropFilter: "blur(20px)",
    borderBottom: `1px solid ${scrolled ? "#1e1e3a" : "transparent"}`,
    transition: "all 0.3s ease",
  };

  const linkStyle = (path) => ({
    color: isActive(path) ? "#7c6fff" : "#9090b8",
    fontWeight: 600, fontSize: "0.9rem",
    padding: "6px 14px", borderRadius: 8,
    background: isActive(path) ? "rgba(124,111,255,0.1)" : "transparent",
    transition: "all 0.2s", display: "inline-block"
  });

  return (
    <nav style={navStyle}>
      <div className="container" style={{ maxWidth: 1200 }}>
        <div className="d-flex align-items-center justify-content-between" style={{ height: 68 }}>
          <Link to="/" className="d-flex align-items-center gap-2">
            <div style={{
              width: 36, height: 36, borderRadius: 10,
              background: "linear-gradient(135deg, #7c6fff, #00e5b0)",
              display: "flex", alignItems: "center", justifyContent: "center",
              fontFamily: "JetBrains Mono, monospace", fontWeight: 700,
              fontSize: "0.85rem", color: "white"
            }}>{"<>"}</div>
            <span style={{ fontWeight: 800, fontSize: "1.1rem", color: "#f0f0ff" }}>
              Code<span style={{ color: "#7c6fff" }}>Learn</span>
            </span>
          </Link>

          <div className="d-none d-lg-flex align-items-center gap-1">
            <Link to="/" style={linkStyle("/")}>Home</Link>
            <Link to="/courses" style={linkStyle("/courses")}>Courses</Link>
            {isAuthenticated && <Link to="/my-courses" style={linkStyle("/my-courses")}>My Learning</Link>}
          </div>

          <div className="d-none d-lg-flex align-items-center gap-2">
            {isAuthenticated ? (
              <>
                <div className="d-flex align-items-center gap-2 px-3 py-2 rounded-3"
                  style={{ background: "#13132a", border: "1px solid #1e1e3a" }}>
                  <div style={{
                    width: 30, height: 30, borderRadius: "50%",
                    background: "linear-gradient(135deg, #7c6fff, #ff6b9d)",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontWeight: 800, fontSize: "0.8rem", color: "white"
                  }}>{user?.name?.charAt(0).toUpperCase()}</div>
                  <span style={{ color: "#9090b8", fontSize: "0.88rem", fontWeight: 600 }}>
                    {user?.name?.split(" ")[0]}
                  </span>
                </div>
                <button onClick={handleLogout} className="btn btn-ghost btn-sm px-3">
                  <i className="bi bi-box-arrow-right me-1"></i>Logout
                </button>
              </>
            ) : (
              <>
                <Link to="/login" className="btn btn-ghost btn-sm px-4">Log In</Link>
                <Link to="/signup" className="btn btn-glow btn-sm px-4">Sign Up</Link>
              </>
            )}
          </div>

          <button className="d-lg-none btn" onClick={() => setMenuOpen(!menuOpen)}
            style={{ color: "#9090b8", border: "1px solid #1e1e3a", borderRadius: 8, padding: "6px 10px" }}>
            <i className={`bi ${menuOpen ? "bi-x-lg" : "bi-list"} fs-5`}></i>
          </button>
        </div>

        {menuOpen && (
          <div className="d-lg-none pb-4 d-flex flex-column gap-2"
            style={{ borderTop: "1px solid #1e1e3a", paddingTop: 16 }}>
            <Link to="/" onClick={() => setMenuOpen(false)} style={linkStyle("/")}>Home</Link>
            <Link to="/courses" onClick={() => setMenuOpen(false)} style={linkStyle("/courses")}>Courses</Link>
            {isAuthenticated && <Link to="/my-courses" onClick={() => setMenuOpen(false)} style={linkStyle("/my-courses")}>My Learning</Link>}
            <div className="d-flex gap-2 mt-2">
              {isAuthenticated ? (
                <button onClick={handleLogout} className="btn btn-ghost btn-sm flex-grow-1">Logout</button>
              ) : (
                <>
                  <Link to="/login" onClick={() => setMenuOpen(false)} className="btn btn-ghost btn-sm flex-grow-1">Log In</Link>
                  <Link to="/signup" onClick={() => setMenuOpen(false)} className="btn btn-glow btn-sm flex-grow-1">Sign Up</Link>
                </>
              )}
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
